bool repeatedSubstringPattern(char* s) {
    int n=strlen(s); if(n<2) return false;
    char* t=malloc(2*n+1); strcpy(t,s); strcat(t,s);
    t[2*n]=0;
    char* p=strstr(t+1,s);
    int ok = p && p < t+n;
    free(t); return ok;
}
